const requestMeta = $node['Build Request'].json;
const response = $input.item.json;
const envelope = response?.body ?? response;
const statusCode = envelope?.statusCode ?? response?.statusCode ?? null;
const success = typeof statusCode === 'number' ? statusCode >= 200 && statusCode < 400 && !response?.error : false;
const attempts = [...(requestMeta.attempts || [])];
attempts.push({
  step: 'local',
  success,
  statusCode,
  error: response?.error ?? null,
  reason: success ? 'handled locally' : 'local-call-failed',
  timestamp: new Date().toISOString()
});
const payload = envelope?.body ?? envelope?.data ?? null;
return [{
  json: {
    request: requestMeta.request,
    prompt: requestMeta.prompt,
    sessionId: requestMeta.sessionId,
    attempts,
    success,
    localResponse: payload,
    statusCode,
    lastStep: 'local'
  }
}];

