const prior = $node['Audit Local'].json;
const response = $input.item.json;
const envelope = response?.body ?? response;
const statusCode = envelope?.statusCode ?? response?.statusCode ?? null;
const success = typeof statusCode === 'number' ? statusCode >= 200 && statusCode < 400 && !response?.error : false;
const attempts = [...(prior.attempts || [])];
attempts.push({
  step: 'nvidia',
  success,
  statusCode,
  error: response?.error ?? null,
  reason: success ? 'nvidia-fallback' : 'nvidia-call-failed',
  timestamp: new Date().toISOString()
});
const payload = envelope?.body?.choices?.[0]?.message?.content ?? envelope?.body ?? envelope?.data ?? null;
return [{
  json: {
    request: prior.request,
    prompt: prior.prompt,
    sessionId: prior.sessionId,
    attempts,
    success,
    nvidiaResponse: payload,
    statusCode,
    lastStep: 'nvidia'
  }
}];

const nodeData = $input.item.json;
const deterministicAnswer = `Deterministic fallback for "${nodeData.prompt}" while remote services recover.`;
const attempts = [...(nodeData.attempts || [])];
attempts.push({
  step: 'deterministic',
  success: true,
  statusCode: 200,
  reason: 'deterministic-answer',
  timestamp: new Date().toISOString()
});
return [{ json: { decision: 'deterministic', payload: deterministicAnswer, fallbackAudit: attempts, metadata: { prompt: nodeData.prompt, sessionId: nodeData.sessionId, statusCode: 200, path: 'deterministic' } } }];

