const payload = $input.first().json;
const attempts = Array.isArray(payload.fallbackAudit) ? payload.fallbackAudit : [];
const icon = payload.decision === 'local'
  ? ':white_check_mark:'
  : payload.decision === 'nvidia'
    ? ':satellite:'
    : ':warning:';
const lines = [
  `${icon} *Inference Router* ${String(payload.decision || 'unknown').toUpperCase()}`,
  `Session: ${payload.metadata?.sessionId || 'unknown'}`,
  `Path: ${payload.metadata?.path || payload.decision}`,
  `Status: ${payload.metadata?.statusCode || 'n/a'}`,
  `Attempts: ${attempts.map((attempt) => `${attempt.step}:${attempt.success ? 'ok' : 'fail'}`).join(', ') || 'none'}`
];
return [{
  json: {
    ...payload,
    slackNotification: {
      skip: false,
      channel: 'C0ALX8C12TG',
      text: lines.join('\n')
    }
  }
}];
